```typescript
// 如果使用 PostgreSQL/MySQL 等数据库
async transfer(fromUserId: string, toUserId: string, amount: number): Promise<Transaction> {
  const client = await pool.connect();

  try {
    await client.query('BEGIN');

    // 使用 SELECT FOR UPDATE 获取行级锁
    const fromAccount = await client.query(
      'SELECT * FROM accounts WHERE user_id = $1 FOR UPDATE',
      [fromUserId]
    );

    const toAccount = await client.query(
      'SELECT * FROM accounts WHERE user_id = $1 FOR UPDATE',
      [toUserId]
    );

    // 执行转账逻辑
    // ...

    await client.query('COMMIT');
    return transaction;
  } catch (error) {
